import{_ as s,c as o,o as e,a}from"./app.04967549.js";const n='{"title":"Note","description":"","frontmatter":{},"headers":[{"level":2,"title":".d.ts File","slug":"d-ts-file"},{"level":2,"title":"Module Output Options","slug":"module-output-options"},{"level":3,"title":"例子","slug":"例子"},{"level":2,"title":"Module Resolution","slug":"module-resolution"},{"level":3,"title":"How Node.js resolves modules","slug":"how-node-js-resolves-modules"},{"level":3,"title":"Additional module resolution flags","slug":"additional-module-resolution-flags"}],"relativePath":"docs/typescript/note.md"}',l={},p=[a('<h1 id="note" tabindex="-1">Note <a class="header-anchor" href="#note" aria-hidden="true">#</a></h1><h2 id="d-ts-file" tabindex="-1"><code>.d.ts</code> File <a class="header-anchor" href="#d-ts-file" aria-hidden="true">#</a></h2><p>需要注意，用TypeScript写的模块再发布时仍采用的是JavaScript发布，这就会导致一个问题：TypeScript中的类型数据都丢失了，所以就需要编译器在把<code>.ts</code>文件编译成<code>.js</code>文件时，同时可以生成一个<code>.d.ts</code>文件，来标记生成的<code>.js</code>文件中的对象的类型</p><blockquote><p>当别人使用你的模块时，代码组成就是js和.d.ts,其他开发者在使用你的模块时也能获取到类型提示等</p></blockquote><p>类型定义和运行时实现，TypeScript 可以自动分别从 *.d.ts 和 *.js 中获取</p><p>当 TypeScript 脚本被编译时，有一个选项可以生成一个声明文件（扩展名为 .d.ts），作为编译后的 JavaScript 中组件的接口。 在此过程中，编译器剥离所有函数和方法主体，仅保留导出类型的签名。 然后，当第三方开发人员从 TypeScript 使用它时，生成的声明文件可用于描述 JavaScript 库或模块的导出虚拟 TypeScript 类型</p><h2 id="module-output-options" tabindex="-1">Module Output Options <a class="header-anchor" href="#module-output-options" aria-hidden="true">#</a></h2><p>There are two options which affect the emitted JavaScript output:</p><ul><li><p><a href="https://www.typescriptlang.org/tsconfig#target" target="_blank" rel="noopener noreferrer"><code>target</code></a> which determines which JS features are downleveled (converted to run in older JavaScript runtimes) and which are left intact</p><blockquote><p>决定了哪些JS特性被降级（为了兼容性）</p></blockquote></li><li><p><a href="https://www.typescriptlang.org/tsconfig#module" target="_blank" rel="noopener noreferrer"><code>module</code></a> which determines what code is used for modules to interact with each other</p><blockquote><p>决定了模块之间使用什么代码进行交互</p></blockquote></li></ul><p>您使用哪一个<a href="https://www.typescriptlang.org/tsconfig#target" target="_blank" rel="noopener noreferrer"><code>target</code></a>取决于您希望在其中运行 TypeScript 代码的 JavaScript 运行时中可用的功能。这可能是：您支持的最旧的 Web 浏览器、您希望运行的 Node.js 的最低版本或可能来自独特的运行时的约束（例如 Electron）</p><p>模块之间的所有通信都通过模块加载器进行，编译器选项<a href="https://www.typescriptlang.org/tsconfig#module" target="_blank" rel="noopener noreferrer"><code>module</code></a>决定使用哪一个, 在运行时，模块加载器负责在执行模块之前定位和执行模块的所有依赖项</p><h3 id="例子" tabindex="-1">例子 <a class="header-anchor" href="#例子" aria-hidden="true">#</a></h3><p>举个简单的例子：</p><div class="language-ts"><pre><code><span class="line"><span style="color:#676E95;font-style:italic;">// .ts file</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">valueOfPi</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">./constants.js</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#A6ACCD;"> </span></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">export</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> twoPi </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> valueOfPi </span><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">2</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span></code></pre></div><p>下面将展示module选项不同时，输出的不同</p><h4 id="es2020" tabindex="-1">ES2020 <a class="header-anchor" href="#es2020" aria-hidden="true">#</a></h4><div class="language-js"><pre><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">valueOfPi</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">./constants.js</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;font-style:italic;">export</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> twoPi </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> valueOfPi </span><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">2</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span></code></pre></div><h4 id="commonjs" tabindex="-1">CommonJS <a class="header-anchor" href="#commonjs" aria-hidden="true">#</a></h4><div class="language-js"><pre><code><span class="line"><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">use strict</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#FFCB6B;">Object</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">defineProperty</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">exports,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">__esModule</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> </span><span style="color:#F07178;">value</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FF9CAC;">true</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">exports.</span><span style="color:#A6ACCD;">twoPi </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">void</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> constants_js_1 </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">require</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">./constants.js</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">exports.</span><span style="color:#A6ACCD;">twoPi </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> constants_js_1</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">valueOfPi </span><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">2</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span></code></pre></div><h4 id="umd" tabindex="-1">UMD <a class="header-anchor" href="#umd" aria-hidden="true">#</a></h4><div class="language-js"><pre><code><span class="line"><span style="color:#A6ACCD;">(</span><span style="color:#C792EA;">function</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">factory</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#F07178;"> (</span><span style="color:#89DDFF;">typeof</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">module</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">===</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">object</span><span style="color:#89DDFF;">&quot;</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&amp;&amp;</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">typeof</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">module.exports</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">===</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">object</span><span style="color:#89DDFF;">&quot;</span><span style="color:#F07178;">) </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#F07178;">        </span><span style="color:#C792EA;">var</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">v</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#82AAFF;">factory</span><span style="color:#F07178;">(</span><span style="color:#A6ACCD;">require</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">exports</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#F07178;">        </span><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#F07178;"> (</span><span style="color:#A6ACCD;">v</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">!==</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">undefined</span><span style="color:#F07178;">) </span><span style="color:#89DDFF;">module.exports</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">v</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">}</span></span>\n<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">else</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;font-style:italic;">if</span><span style="color:#F07178;"> (</span><span style="color:#89DDFF;">typeof</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">define</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">===</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">function</span><span style="color:#89DDFF;">&quot;</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&amp;&amp;</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">define</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">amd</span><span style="color:#F07178;">) </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#F07178;">        </span><span style="color:#82AAFF;">define</span><span style="color:#F07178;">([</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">require</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">exports</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">./constants.js</span><span style="color:#89DDFF;">&quot;</span><span style="color:#F07178;">]</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">factory</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">}</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)(</span><span style="color:#C792EA;">function</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">require</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> exports</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">use strict</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#F07178;">    </span><span style="color:#FFCB6B;">Object</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">defineProperty</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">exports,</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">__esModule</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> value</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> </span><span style="color:#FF9CAC;">true</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">}</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">exports.</span><span style="color:#A6ACCD;">twoPi</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">void</span><span style="color:#F07178;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#F07178;">    </span><span style="color:#C792EA;">const</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">constants_js_1</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#82AAFF;">require</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">./constants.js</span><span style="color:#89DDFF;">&quot;</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">exports.</span><span style="color:#A6ACCD;">twoPi</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">constants_js_1</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">valueOfPi</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">*</span><span style="color:#F07178;"> </span><span style="color:#F78C6C;">2</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"></span></code></pre></div><h2 id="module-resolution" tabindex="-1">Module Resolution <a class="header-anchor" href="#module-resolution" aria-hidden="true">#</a></h2><p>There are two possible module resolution strategies: <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#node" target="_blank" rel="noopener noreferrer">Node</a> and <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#classic" target="_blank" rel="noopener noreferrer">Classic</a>. You can use the <a href="https://www.typescriptlang.org/tsconfig#moduleResolution" target="_blank" rel="noopener noreferrer"><code>moduleResolution</code></a> option to specify the module resolution strategy. If not specified, the default is <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#node" target="_blank" rel="noopener noreferrer">Node</a> for <code>--module commonjs</code>, and <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#classic" target="_blank" rel="noopener noreferrer">Classic</a> otherwise (including when <a href="https://www.typescriptlang.org/tsconfig#module" target="_blank" rel="noopener noreferrer"><code>module</code></a> is set to <code>amd</code>, <code>system</code>, <code>umd</code>, <code>es2015</code>, <code>esnext</code>, etc.).</p><blockquote><p>Note: <code>node</code> module resolution is the most-commonly used in the TypeScript community and is recommended for most projects. If you are having resolution problems with <code>import</code>s and <code>export</code>s in TypeScript, try setting <code>moduleResolution: &quot;node&quot;</code> to see if it fixes the issue.</p></blockquote><h3 id="how-node-js-resolves-modules" tabindex="-1">How Node.js resolves modules <a class="header-anchor" href="#how-node-js-resolves-modules" aria-hidden="true">#</a></h3><p>To understand what steps the TS compiler will follow, it is important to shed some light on Node.js modules. Traditionally, imports in Node.js are performed by calling a function named <code>require</code>. The behavior Node.js takes will differ depending on if <code>require</code> is given a relative path or a non-relative path.</p><blockquote><p>相对路径的模块</p></blockquote><p>Relative paths are fairly straightforward. As an example, let’s consider a file located at <code>/root/src/moduleA.js</code>, which contains the import <code>var x = require(&quot;./moduleB&quot;);</code> Node.js resolves that import in the following order:</p><ol><li>Ask the file named <code>/root/src/moduleB.js</code>, if it exists.</li><li>Ask the folder <code>/root/src/moduleB</code> if it contains a file named <code>package.json</code> that specifies a <code>&quot;main&quot;</code> module. In our example, if Node.js found the file <code>/root/src/moduleB/package.json</code> containing <code>{ &quot;main&quot;: &quot;lib/mainModule.js&quot; }</code>, then Node.js will refer to <code>/root/src/moduleB/lib/mainModule.js</code>.</li><li>Ask the folder <code>/root/src/moduleB</code> if it contains a file named <code>index.js</code>. That file is implicitly considered that folder’s “main” module.</li></ol><p>You can read more about this in Node.js documentation on <a href="https://nodejs.org/api/modules.html#modules_file_modules" target="_blank" rel="noopener noreferrer">file modules</a> and <a href="https://nodejs.org/api/modules.html#modules_folders_as_modules" target="_blank" rel="noopener noreferrer">folder modules</a>.</p><blockquote><p>非相对路径的模块</p></blockquote><p>However, resolution for a <a href="https://www.typescriptlang.org/docs/handbook/module-resolution.html#relative-vs-non-relative-module-imports" target="_blank" rel="noopener noreferrer">non-relative module name</a> is performed differently. Node will look for your modules in special folders named <code>node_modules</code>. A <code>node_modules</code> folder can be on the same level as the current file, or higher up in the directory chain. Node will walk up the directory chain, looking through each <code>node_modules</code> until it finds the module you tried to load.</p><p>Following up our example above, consider if <code>/root/src/moduleA.js</code> instead used a non-relative path and had the import <code>var x = require(&quot;moduleB&quot;);</code>. Node would then try to resolve <code>moduleB</code> to each of the locations until one worked.</p><ol><li><p><code>/root/src/node_modules/moduleB.js</code></p></li><li><p><code>/root/src/node_modules/moduleB/package.json</code> (if it specifies a <code>&quot;main&quot;</code> property)</p></li><li><p><code>/root/src/node_modules/moduleB/index.js</code></p></li><li><p><code>/root/node_modules/moduleB.js</code></p></li><li><p><code>/root/node_modules/moduleB/package.json</code> (if it specifies a <code>&quot;main&quot;</code> property)</p></li><li><p><code>/root/node_modules/moduleB/index.js</code></p></li><li><p><code>/node_modules/moduleB.js</code></p></li><li><p><code>/node_modules/moduleB/package.json</code> (if it specifies a <code>&quot;main&quot;</code> property)</p></li><li><p><code>/node_modules/moduleB/index.js</code></p></li></ol><p>Notice that Node.js jumped up a directory in steps (4) and (7).</p><p>You can read more about the process in Node.js documentation on <a href="https://nodejs.org/api/modules.html#modules_loading_from_node_modules_folders" target="_blank" rel="noopener noreferrer">loading modules from <code>node_modules</code></a>.</p><h3 id="additional-module-resolution-flags" tabindex="-1">Additional module resolution flags <a class="header-anchor" href="#additional-module-resolution-flags" aria-hidden="true">#</a></h3><h4 id="base-url" tabindex="-1">Base URL <a class="header-anchor" href="#base-url" aria-hidden="true">#</a></h4><p><strong>Setting <a href="https://www.typescriptlang.org/tsconfig#baseUrl" target="_blank" rel="noopener noreferrer"><code>baseUrl</code></a> informs the compiler where to find modules.</strong></p><p>All module imports with <strong>non-relative names</strong> are assumed to be relative to the <a href="https://www.typescriptlang.org/tsconfig#baseUrl" target="_blank" rel="noopener noreferrer"><code>baseUrl</code></a>.</p><blockquote><p>具有相对路径的模块则直接按照上面已经提到过的方式去查 Note that relative module imports are <strong>not impacted</strong> by setting the <code>baseUrl</code>, as they are always resolved relative to their importing files. 换句话说，自己在项目中写的模块是不受Base URL的影响的</p></blockquote><h4 id="path-mapping" tabindex="-1">Path mapping <a class="header-anchor" href="#path-mapping" aria-hidden="true">#</a></h4><p>Sometimes modules are not directly located under <em>baseUrl</em>. For instance, an import to a module <code>&quot;jquery&quot;</code> would be translated at runtime to <code>&quot;node_modules/jquery/dist/jquery.slim.min.js&quot;</code>. Loaders use a mapping configuration to map module names to files at run-time.</p><p>The TypeScript compiler supports the declaration of such mappings using <a href="https://www.typescriptlang.org/tsconfig#paths" target="_blank" rel="noopener noreferrer"><code>paths</code></a> property in <code>tsconfig.json</code> files. Here is an example for how to specify the <a href="https://www.typescriptlang.org/tsconfig#paths" target="_blank" rel="noopener noreferrer"><code>paths</code></a> property for <code>jquery</code>.</p><div class="language-json"><pre><code><span class="line"><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">compilerOptions</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">baseUrl</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">.</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">// This must be specified if &quot;paths&quot; is.</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">paths</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">      </span><span style="color:#89DDFF;">&quot;</span><span style="color:#F78C6C;">jquery</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">[</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">node_modules/jquery/dist/jquery</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">// This mapping is relative to &quot;baseUrl&quot;</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">}</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">}</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span></code></pre></div><p><strong>Please notice that <a href="https://www.typescriptlang.org/tsconfig#paths" target="_blank" rel="noopener noreferrer"><code>paths</code></a> are resolved relative to <a href="https://www.typescriptlang.org/tsconfig#baseUrl" target="_blank" rel="noopener noreferrer"><code>baseUrl</code></a>.</strong></p><p>When setting <a href="https://www.typescriptlang.org/tsconfig#baseUrl" target="_blank" rel="noopener noreferrer"><code>baseUrl</code></a> to a value other than <code>&quot;.&quot;</code>, i.e. the directory of <code>tsconfig.json</code>, the mappings must be changed accordingly. Say, you set <code>&quot;baseUrl&quot;: &quot;./src&quot;</code> in the above example, then jquery should be mapped to <code>&quot;../node_modules/jquery/dist/jquery&quot;</code>.</p><p>Using <a href="https://www.typescriptlang.org/tsconfig#paths" target="_blank" rel="noopener noreferrer"><code>paths</code></a> also allows for more sophisticated mappings including multiple fall back locations. Consider a project configuration where only some modules are available in one location, and the rest are in another. A build step would put them all together in one place. The project layout may look like:</p><div class="language-"><pre><code>projectRoot\n├── folder1\n│   ├── file1.ts (imports &#39;folder1/file2&#39; and &#39;folder2/file3&#39;)\n│   └── file2.ts\n├── generated\n│   ├── folder1\n│   └── folder2\n│       └── file3.ts\n└── tsconfig.json\n</code></pre></div><p>The corresponding <code>tsconfig.json</code> would look like:</p><div class="language-json"><pre><code><span class="line"><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">compilerOptions</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">baseUrl</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">.</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">paths</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">      </span><span style="color:#89DDFF;">&quot;</span><span style="color:#F78C6C;">*</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">[</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">*</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">generated/*</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">]</span></span>\n<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">}</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">}</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span></code></pre></div><blockquote><p>注意<code>&quot;*&quot;: [&quot;*&quot;, &quot;generated/*&quot;]</code> baseUrl为<code>.</code>,相当于已经自动跟了个<code>/</code>，所以解析的路径相当于是<code>./*/</code>和<code>./generated/</code></p></blockquote>',52)];var t=s(l,[["render",function(s,a,n,l,t,r){return e(),o("div",null,p)}]]);export{n as __pageData,t as default};
